using UnityEngine;
using UnityEditor;

public class ResizeBackground
{
    [MenuItem("Tools/Resize Background")]
    public static void Execute()
    {
        var bgGO = GameObject.Find("MapBackground");
        if (bgGO == null) { Debug.LogError("MapBackground not found!"); return; }

        var sr = bgGO.GetComponent<SpriteRenderer>();
        if (sr == null || sr.sprite == null) { Debug.LogError("No sprite!"); return; }

        // Camera: orthographic, size=15, Y=5
        float cameraHeight = 2f * 15f; // 30
        float cameraWidth = cameraHeight * (16f / 9f); // ~53.33

        float spriteWidth = sr.sprite.bounds.size.x;
        float spriteHeight = sr.sprite.bounds.size.y;

        // Non-uniform stretch to fill camera view
        float scaleX = (cameraWidth / spriteWidth) * 1.02f;
        float scaleY = (cameraHeight / spriteHeight) * 1.02f;

        Undo.RecordObject(bgGO.transform, "Resize MapBackground");
        bgGO.transform.localScale = new Vector3(scaleX, scaleY, 1f);
        bgGO.transform.position = new Vector3(0f, 5f, 0f);

        Debug.Log($"Resized MapBackground. Sprite: {spriteWidth}x{spriteHeight}, Scale: ({scaleX}, {scaleY})");

        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(
            UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene());
    }
}

using UnityEditor;
