        EditorSceneManager.SaveScene(scene);
        Debug.Log($"Saved: {scene.path}");
    }
}

using UnityEngine;
using UnityEditor;

public class AddShopBackground
{
    [MenuItem("Tools/Add Shop Background")]
    public static void Execute()
    {
        // Remove existing background if any
        var existing = GameObject.Find("ShopBackground");
        if (existing != null)
        {
            Undo.DestroyObjectImmediate(existing);
        }

        // Create background GameObject
        var bgGO = new GameObject("ShopBackground");
        Undo.RegisterCreatedObjectUndo(bgGO, "Create ShopBackground");

        var sr = bgGO.AddComponent<SpriteRenderer>();
        var sprite = AssetDatabase.LoadAssetAtPath<Sprite>("Assets/Sprites/Fondos/tienda_01.png");
        if (sprite == null)
        {
            Debug.LogError("Could not load tienda_01.png");
            return;
        }

        sr.sprite = sprite;
        sr.sortingOrder = -10;

        // Camera: orthographic, size=5, position=(0, 0)
        float cameraHeight = 2f * 5f; // 10
        float cameraWidth = cameraHeight * (16f / 9f); // ~17.78

        float spriteWidth = sprite.bounds.size.x;
        float spriteHeight = sprite.bounds.size.y;

        float scaleX = (cameraWidth / spriteWidth) * 1.02f;
        float scaleY = (cameraHeight / spriteHeight) * 1.02f;

        bgGO.transform.localScale = new Vector3(scaleX, scaleY, 1f);
        bgGO.transform.position = new Vector3(0f, 0f, 0f);

        // Add BackgroundScaler for runtime adaptation
        bgGO.AddComponent<BackgroundScaler>();

        Debug.Log($"ShopBackground created. Sprite: {spriteWidth}x{spriteHeight}, Scale: ({scaleX}, {scaleY})");

        UnityEditor.SceneManagement.EditorSceneManager.MarkSceneDirty(
            UnityEditor.SceneManagement.EditorSceneManager.GetActiveScene());
    }
}

